    wwv_flow_api.g_varchar2_table(527) := 'nsrsid11348159\charrsid10370899 ART\''cdCULO 405. Devoluci\''f3n de saldos a favor.}{\rtlch\fcs1 \ai\a';
    wwv_flow_api.g_varchar2_table(528) := 'f1 \ltrch\fcs0 \cs23\i\f1\insrsid11348159\charrsid10370899 '||wwv_flow.LF||
' Los contribuyentes de los tributos admi';
    wwv_flow_api.g_varchar2_table(529) := 'nistrados por la Administraci\''f3n Tributaria Distrital, podr\''e1n solicitar la devoluci\''f3n o comp';
    wwv_flow_api.g_varchar2_table(530) := 'ensaci\''f3'||wwv_flow.LF||
'n de los saldos a favor originados en las declaraciones, en pagos en exceso o de lo no de';
    wwv_flow_api.g_varchar2_table(531) := 'bido, de conformidad con el tr\''e1mite se\''f1alado en los art\''edculos siguientes.}{\rtlch\fcs1 \af1';
    wwv_flow_api.g_varchar2_table(532) := ' \ltrch\fcs0 \f1\insrsid11348159\charrsid10370899 '||wwv_flow.LF||
'\par }{\rtlch\fcs1 \ab\ai\af1 \ltrch\fcs0 \cs23\b';
    wwv_flow_api.g_varchar2_table(533) := '\i\f1\ul\insrsid11348159\charrsid10370899 En todos los casos, la devoluci\''f3n de saldos a favor se ';
    wwv_flow_api.g_varchar2_table(534) := 'efectuar\''e1 una vez compensadas las deudas y obligaciones de plazo vencido del contribuyente}{\rtlc';
    wwv_flow_api.g_varchar2_table(535) := 'h\fcs1 '||wwv_flow.LF||
'\ai\af1 \ltrch\fcs0 \cs23\i\f1\insrsid11348159\charrsid10370899 . En el mismo acto que orden';
    wwv_flow_api.g_varchar2_table(536) := 'e la devoluci\''f3n, se compensar\''e1n las deudas y obligaciones a cargo del contribuyente...\''94 (Ne';
    wwv_flow_api.g_varchar2_table(537) := 'grillas y subrayado fuera del texto)}{\rtlch\fcs1 \af1 '||wwv_flow.LF||
'\ltrch\fcs0 \f1\insrsid11348159\charrsid1037';
    wwv_flow_api.g_varchar2_table(538) := '0899 '||wwv_flow.LF||
