    wwv_flow_api.g_varchar2_table(539) := '\aspnum\faauto\adjustright\rin0\lin0\itap0\pararsid11348159 {\rtlch\fcs1 \af1 \ltrch\fcs0 \f1\insrsi';
    wwv_flow_api.g_varchar2_table(540) := 'd11348159\charrsid10370899 Que el Art\''edcul'||wwv_flow.LF||
'o 381 del Estatuto Distrital Tributario - Decreto No. 0';
    wwv_flow_api.g_varchar2_table(541) := '180 de 2010 renumerado por el Decreto No. 0924 de 2011, depreca:'||wwv_flow.LF||
'\par }\pard \ltrpar\s21\qj \li600\r';
    wwv_flow_api.g_varchar2_table(542) := 'i0\sb100\sa100\sbauto1\saauto1\widctlpar\wrapdefault\aspalpha\aspnum\faauto\adjustright\rin0\lin600\';
    wwv_flow_api.g_varchar2_table(543) := 'itap0\pararsid11348159 {\rtlch\fcs1 \ai\af1 \ltrch\fcs0 \cs23\i\f1\insrsid11348159\charrsid10370899 ';
    wwv_flow_api.g_varchar2_table(544) := '\''93\''85 }{\rtlch\fcs1 '||wwv_flow.LF||
'\ab\ai\af1 \ltrch\fcs0 \cs22\b\i\f1\insrsid11348159\charrsid10370899 ART\''cd';
    wwv_flow_api.g_varchar2_table(545) := 'CULO 381.}{\rtlch\fcs1 \ai\af1 \ltrch\fcs0 \cs23\i\f1\insrsid11348159\charrsid10370899  }{\rtlch\fcs';
    wwv_flow_api.g_varchar2_table(546) := '1 \ab\ai\af1 \ltrch\fcs0 \cs22\b\i\f1\insrsid11348159\charrsid10370899 '||wwv_flow.LF||
'Fecha en que se entiende pag';
    wwv_flow_api.g_varchar2_table(547) := 'ado el impuesto}{\rtlch\fcs1 \ai\af1 \ltrch\fcs0 \cs23\i\f1\insrsid11348159\charrsid10370899 . Se te';
    wwv_flow_api.g_varchar2_table(548) := 'ndr\''e1 como fecha de pago del impuesto respecto de cada contribuyente, '||wwv_flow.LF||
'aquella en que los valores ';
    wwv_flow_api.g_varchar2_table(549) := 'imputables hayan ingresados a las oficinas de los impuestos o a los Bancos autorizados, a\''fan en lo';
    wwv_flow_api.g_varchar2_table(550) := 's casos en que se hayan recibido inicialmente como simples dep\''f3'||wwv_flow.LF||
'sitos, buenas cuentas, retencione';
    wwv_flow_api.g_varchar2_table(551) := 's en la fuente, o que resulten como saldos a su favor por cualquier concepto\''85\''94}{\rtlch\fcs1 \a';
    wwv_flow_api.g_varchar2_table(552) := 'f1 \ltrch\fcs0 \f1\insrsid11348159\charrsid10370899 '||wwv_flow.LF||
'\par }\pard \ltrpar\s21\qj \li0\ri0\sb100\sa100';
    wwv_flow_api.g_varchar2_table(553) := '\sbauto1\saauto1\widctlpar\wrapdefault\aspalpha\aspnum\faauto\adjustright\rin0\lin0\itap0\pararsid11';
    wwv_flow_api.g_varchar2_table(554) := '348159 {\rtlch\fcs1 \af1 \ltrch\fcs0 \f1\insrsid11348159\charrsid10370899 '||wwv_flow.LF||
'Que al consultar el Siste';
    wwv_flow_api.g_varchar2_table(555) := 'ma de Informaci\''f3n Tributaria (S.I.T.), correspondiente a los predios bajo estudio, se observa que';
    wwv_flow_api.g_varchar2_table(556) := ' no fungen con deudas tributarias de plazo vencido.'||wwv_flow.LF||
'\par Que corresponde a los funcionarios previame';
    wwv_flow_api.g_varchar2_table(557) := 'nte autorizados o comisionados, estudiar, verificar las solicitudes de devoluci\''f3n y/o compensaci\';
    wwv_flow_api.g_varchar2_table(558) := '''f3'||wwv_flow.LF||
'n y proyectar los fallos, y en general todas las actuaciones preparatorias y necesarias para pro';
    wwv_flow_api.g_varchar2_table(559) := 'ferir los actos de competencia del Asesor del Despacho del Grupo de Recaudo o quien haga sus veces.'||wwv_flow.LF||
'';
    wwv_flow_api.g_varchar2_table(560) := '\par Que de conformidad con los Art\''edculos 1\''ba de las Resoluciones No. 005 y 006 de Enero 25 de ';
    wwv_flow_api.g_varchar2_table(561) := '2012, al Asesor del Despacho del Grupo de Recaudo le fueron delegadas funciones por el Gerente de Ge';
    wwv_flow_api.g_varchar2_table(562) := 'sti\''f3n de Ingresos de profe'||wwv_flow.LF||
'rir los actos para ordenar, rechazar, negar las devoluciones y las com';
    wwv_flow_api.g_varchar2_table(563) := 'pensaciones en los casos y por los procedimientos establecidos en el Titulo X del Estatuto Tributari';
    wwv_flow_api.g_varchar2_table(564) := 'o Distrital, y de revocar de oficio las Liquidaciones Oficiales factura o recibos ofi'||wwv_flow.LF||
'ciales de pago';
    wwv_flow_api.g_varchar2_table(565) := ' por cambios de aval\''fao, cambio de estrato, cambio de destino, entre otros, cuyo monto no exceda d';
    wwv_flow_api.g_varchar2_table(566) := 'e Diez Millones de Pesos ($10.000.000), para cada caso.'||wwv_flow.LF||
'\par Que revisados los documentos aportados ';
    wwv_flow_api.g_varchar2_table(567) := 'y de conformidad con las normas tributarias relacionadas anteriormente este Despacho luego de examin';
    wwv_flow_api.g_varchar2_table(568) := 'ar los fundamentos jur\''eddicos planteados por el contribuyente y la situaci\''f3n f\''e1ctica, se con';
    wwv_flow_api.g_varchar2_table(569) := 'cluye que }{'||wwv_flow.LF||
'\rtlch\fcs1 \ab\af1 \ltrch\fcs0 \cs22\b\f1\ul\insrsid11348159\charrsid10370899 es viabl';
    wwv_flow_api.g_varchar2_table(570) := 'e la solicitud formulada}{\rtlch\fcs1 \af1 \ltrch\fcs0 \f1\insrsid11348159\charrsid10370899 .'||wwv_flow.LF||
'\par E';
    wwv_flow_api.g_varchar2_table(571) := 'n m\''e9rito de lo anterior, este Despacho'||wwv_flow.LF||
'\par }\pard \ltrpar\s21\qc \li0\ri0\sb100\sa100\sbauto1\sa';
